class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        long max = 0;
        for (int l = 0; l < n; l++) {
            long[] dp = new long[k + 1];
            long g = 0;
            for (int r = l; r < n; r++) {
                long v = nums[r];
                long g2 = gcd(g, v);
                long g3 = gcd(g, 2 * v);
                long[] ndp = new long[k + 1];
                for (int j = 0; j <= k; j++) {
                    ndp[j] = Math.max(ndp[j], dp[j] * g2 / g);
                    if (j > 0) {
                        ndp[j] = Math.max(ndp[j], dp[j - 1] * g3 / g);
                    }
                }
                ndp[0] = Math.max(ndp[0], g2);
                if (k > 0) ndp[1] = Math.max(ndp[1], g3);
                dp = ndp;
                g = g2;
                for (int j = 0; j <= k; j++) {
                    max = Math.max(max, dp[j] * (r - l + 1));
                }
            }
        }
        return max;
    }

    private long gcd(long a, long b) {
        while (b != 0) {
            long t = b;
            b = a % b;
            a = t;
        }
        return a;
    }
}
